var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>왕립교정국</color> 산하 A레벨 수용소","JPN":"<color=#ffd34c>王立矯正局</color>傘下のレベルA収容所","ENG":"<color=#ffd34c>Royal Correctional Department</color> Level A Prison","TWN":"<color=#ffd34c>王室矯正局</color>所屬A級收容所"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CULTIST_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"어머니의 보살핌 아래에 우리는 곧 하나가 될 지니.","JPN":"母の腕の中で、我々はもうじき一つになる。","ENG":"Under Mother's care, we will soon become one.","TWN":"在母親的關懷下，我們即將合而為一。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_VATICAN_SUPPLEMENT_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CULTIST_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"모두 죽음을 두려워하지 말지어다.","JPN":"皆、死を恐れるな。","ENG":"Fear not death, everyone.","TWN":"大家不要懼怕死亡。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_VATICAN_SUPPLEMENT_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CULTIST_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"성찬을 준비해라! 새로운 날이 당도하게 될 테니!","JPN":"聖餐の準備をしろ！　新しい日が到来するだろう！","ENG":"Prepare the feast! For a new dawn is coming!","TWN":"預備盛宴吧！新天將來到！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_VATICAN_SUPPLEMENT_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JAILER_PRYDWEN_NPC_NULL","text":{"KOREA":"잠깐, 사격 중지!","JPN":"待て、射撃中止！","ENG":"Wait, cease fire!","TWN":"等一下，停止射擊！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAILER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_02"},{"id":"L16_1","type":"dialog","speaker":"JAILER_PRYDWEN_NPC_NULL","text":{"KOREA":"이 자식들 스스로 자해하기 시작했어!","JPN":"こいつら、自害し始めたぞ！","ENG":"Those bastards started cutting themselves!","TWN":"這些傢伙開始自殘了！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAILER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"OCTOPUS3_ESPR_NULL_NULL","text":{"KOREA":"지식<color=#ff3636>의 성찬</color>이 준비되었<color=#ff3636>다. 연회가</color> 시작<b>되</b>었다.","JPN":"知識<color=#ff3636>の聖餐</color>の準備が整っ<color=#ff3636>た。宴会が</color> 始ま<b>っ</b>た。","ENG":"The fe<color=#ff3636>ast of know</color>ledge has be<color=#ff3636>en prepared. The banquet</color> has st<b>arte</b>d.","TWN":"知識的<color=#ff3636>盛宴</color>準備好了。<color=#ff3636>宴會</color>開始<b>了</b>。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JAILER_PRYDWEN_NPC_NULL","text":{"KOREA":"으, 으아아아악!!","JPN":"う、うわああああっ！！","ENG":"A-AAAAAARGH!!","TWN":"呃，呃啊啊啊啊！！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"JAILER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"JAILER_PRYDWEN_NPC_NULL","text":{"KOREA":"제길, 새로운 부류의 학회 녀석들인가?","JPN":"くそ、新しい類の学会のやつらか？","ENG":"Dammit! Are they some new fraternity of the Society?","TWN":"可惡，是新學會的傢伙嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"JAILER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L26_1","type":"dialog","speaker":"JAILER_PRYDWEN_NPC_NULL","text":{"KOREA":"계속 쏴! 이 구역을 내주면…….","JPN":"撃ち続けろ！　この区域を奪われたら……","ENG":"Keep shooting them! If you give up this zone–","TWN":"繼續射擊！如果這個區域被佔領……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"JAILER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"JAILER_PRYDWEN_NPC_NULL","text":{"KOREA":"으악!","JPN":"うわっ！","ENG":"Aaargh!","TWN":"呃啊！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L32_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"다들 서둘러!","JPN":"みんな、急げ！","ENG":"Hurry!","TWN":"大家快點！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL"},{"id":"L33_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"광신도 녀석들이 시간을 버는 사이에 학부장님을 찾아야 한다!","JPN":"狂信徒のやつらが時間を稼いでいる間に、学部長を探せ！","ENG":"While the enemy is busy dealing with the fanatics, we must rescue the dean!","TWN":"趁著那些瘋狂信徒爭取時間，我們要找到學院院長！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"새로운 학회는 우리 고고학부를 중심으로 결집하는 거다!","JPN":"新しい学会は我が考古学部を中心として結集するのだ！","ENG":"The new Society will be centered around us, the Archeology Department!","TWN":"新學會是以我們考古學院為中心集結的！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"JAILER_PRYDWEN_NPC_NULL","text":{"KOREA":"하, 하하하……! 사, 살려……!","JPN":"は、ははは……！　た、助け……！","ENG":"Ha, hahaha...! Help m–","TWN":"哈，哈哈哈……！救，救命……！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAILER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL"},{"id":"L50_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"학부장님! 저희가 왔습니다! 괜찮으십니까!","JPN":"学部長！　助けに来ました！　ご無事ですか！","ENG":"Dean! We've come to get you out! Are you all right?!","TWN":"學院院長！我們來了！你沒事吧！"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"학부장님! 정신 차리십시오!","JPN":"学部長！　しっかりしてください！","ENG":"Sir! Wake up!","TWN":"學院院長！你醒醒啊！"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L5_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"다들 학부장님을 부축해! 무척 쇠약해지셨다!","JPN":"みんな、学部長を運ぶのを手伝え！　衰弱しておられる！","ENG":"Everyone, help the dean get up! He's too weak!","TWN":"大家扶著學院院長！他現在非常虛弱！"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"쉿……! 호들갑 떨지 말게. 나는 괜찮아.","JPN":"しっ……！　大事にするんじゃない。私は大丈夫だ。","ENG":"Shh...! Don't be so dramatic. I'm all right.","TWN":"噓……！別大驚小怪的，我沒事。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L8_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"학부장님?","JPN":"学部長？","ENG":"Sir...?","TWN":"院長？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"자네, 신탁이라는 걸 들어본 적이 있나?","JPN":"君、神託というのを聞いたことはあるか？","ENG":"Hey, you. Have you ever heard of something called a prophecy?","TWN":"你聽見了神喻嗎？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"……신탁이요?","JPN":"神託……ですか？","ENG":"...A prophecy?","TWN":"……神喻？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"그래. 나는 지금껏 인생을 살아오면서 신의 존재를 믿어본 적이 없어.","JPN":"そう。私はこれまでの人生で、神の存在を信じたことはない。","ENG":"Yes. You see, all my life, I've never once believed in the existence of god.","TWN":"是啊，我活到現在，從來沒有相信過神的存在。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"내가 고고학이라는 학문에 빠져든 것도, 내 의심을 확신으로 바꾸기 위한 여정이었지.","JPN":"私が考古学という学問に熱中したのも、疑いを確信へと変えるための過程だった。","ENG":"Even my journey into the field of archeology was to change my suspicion into certainty.","TWN":"我沉迷於考古這門學問，也是為了將我的懷疑轉化為確信。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"신이란, 결국 나약한 인간이 미지의 공포를 극복하기 위한 허상에 불과하다는 걸 말일세.","JPN":"神とは結局、軟弱な人間が未知への恐怖を克服するための虚像に過ぎないと。","ENG":"To be certain that god is... nothing but a fabrication that weak humans have invented to overcome their fear of the unknown.","TWN":"神，歸根結底，不過是懦弱的人類為克服未知恐懼而創造出的幻影。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"하, 학부장님! 지금은 무신론에 대한 논쟁을 할 시간이 없습니다!","JPN":"が、学部長！　今は無神論について語っている場合ではありません！","ENG":"S-sir! This isn't the time to debate about atheism!","TWN":"院，院長！現在沒有時間爭論這些！"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"기관 녀석들이 곧 여기로 들이닥칠 거라고요!","JPN":"機関のやつらがもうすぐここまで押し寄せてきます！","ENG":"Those Institution bastards will be here any second now!","TWN":"機關的傢伙馬上就要闖進來了！"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"학회에 몸을 담고, 지식의 호수를 좇아왔지만 내 의심은 여전히 해소되지 않았지.","JPN":"学会に所属し知識の湖を追ってきたが、私の疑いは未だ晴れてはいない。","ENG":"I joined the Society to pursue the Lake of Knowledge, but my suspicions were never resolved.","TWN":"我投身於學會，一直追求知識湖水，但我的疑慮仍未消除。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"지식을 탐하면 탐할수록 오히려 더더욱 알 수 없게 되어버렸어.","JPN":"知識を貪るほど、よりわからなくなってしまった。","ENG":"The more I coveted knowledge, the more I got confused.","TWN":"越是貪圖知識，反而越是不得而知。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"그렇다면 그동안 내 인생은 대체 무엇이었던 걸까?","JPN":"では、今までの人生とはいったい、何だったのだろうか。","ENG":"Then, what have I been doing with my life?","TWN":"那麼這段時間我的人生到底是什麼呢？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"학부장님!!","JPN":"学部長！！","ENG":"Sir!!","TWN":"院長！！"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"그러던 와중, 나는 오늘 신탁을 들었네.","JPN":"そんな時、私は今日神託を聞いた。","ENG":"But then, I heard it today. The prophecy.","TWN":"在這種情況下，我今天聽到了神喻。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"아니, 어쩌면 단지 환청이었을지도 모르지. 하지만 나는 똑똑히 속삭임을 들었어.","JPN":"いや、もしかするとただの空耳だったのかもしれない。だが、私はしっかりとそのささやきを聞いたのだ。","ENG":"No, perhaps it was just an auditory hallucination. But I heard it whisper into my ear so clearly.","TWN":"不，也許只是幻覺。但是我聽得很清楚。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"자네들은 어째서! 어떻게! 나를 구하러 온 거지!?","JPN":"君たちはどうして！　どうやって！　私を救いに来た！","ENG":"But WHY?! How did you come to my rescue?!","TWN":"你們為什麼——！會來——！救我？！"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L32_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"학회에 의해 버려진 고고학부의 힘만으로는 나를 구할 수 없었을 텐데!?","JPN":"学会に見捨てられた考古学部の力だけでは、ここまで辿り着くことはできなかったはずだ！！","ENG":"The Archeology Department has been abandoned by the Society, so you couldn't have done it by yourselves!","TWN":"光靠被學會拋棄的考古學院的力量，應該救不了我才對？！"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"그, 그건 <color=#ffd34c>얄다바오트의 자녀들</color>이라는 광신도들이 갑자기…….","JPN":"そ、それは、<color=#ffd34c>ヤルダバオトの子供</color>という狂信徒たちがいきなり……","ENG":"Th-that's because the fanatics who call themselves the <color=#ffd34c>Children of Yaldabaoth</color> suddenly...","TWN":"是，是叫<color=#ffd34c>亞達巴沃的子女</color>的瘋狂信徒們突然找來…."},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_QM","text":{"KOREA":"어째서 네 놈을 여기서 꺼내 주는지…… 그게 궁금한가?","JPN":"どうして貴様をここから出すのか……気になるか？","ENG":"Are you curious to know... why we are getting you out from here?","TWN":"你很好奇……為什麼要把你從這裡救出來，是嗎？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"자네는……?","JPN":"君は……？","ENG":"You're...?","TWN":"你是……？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_QM","text":{"KOREA":"그렇다면 답해주지.","JPN":"答えてやろう。","ENG":"Then I shall answer your question.","TWN":"既然這樣，我就回答你。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_SHADOW","text":{"KOREA":"왜냐하면, 어머니께서 널 필요로 하시기 때문이다.","JPN":"それは、お母さんがお前を必要としているからだ。","ENG":"It is because... Mother requires you.","TWN":"因為，母親需要你。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_SHADOW","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L41_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_SHADOW","text":{"KOREA":"제임스 고고학부장.","JPN":"ジェームス考古学部長。","ENG":"Professor James, Dean of the Archeology Department.","TWN":"詹姆斯考古學院院長。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"허억, 허억, 허억……!","JPN":"はあ、はあ、はあ……！","ENG":"*Huff…!* *Huff…!* *Huff…!*","TWN":"呵，呵，呵……！"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L47_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"학부장님! 힘드시겠지만, 거의 다왔습니다!","JPN":"学部長！　お辛いでしょうが、もうすぐですよ！","ENG":"Sir! We're almost there! Just a little further!","TWN":"院長！我知道你很累，快到了！"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L48_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"밀항을 위해 배편을 잡아놨습니다. 배를 타면 추적을 따돌릴 수 있을 겁니다!","JPN":"密航のために船を手配しておきました。これに乗れば、追手を撒けるはずです！","ENG":"We've prepared a boat to smuggle you out. Once you're on it, they won't be able to track you!","TWN":"為了偷渡，我們已經找好船了。只要坐上船就能甩開追蹤了！"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"그러니 조금만 더, 조금만 더 힘을 내십시오!","JPN":"だから少しだけ、もう少しだけ頑張ってください！","ENG":"So please, just push through a little bit further!","TWN":"所以，請你再堅持一下！"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"학부장님! 배가, 배가 도착했습니다!","JPN":"学部長！　船が、船が到着しました！","ENG":"Sir! The boat! It arrived!","TWN":"院長！船，船到了！"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"아니, 아무래도 한 발 늦은 것 같군.","JPN":"いや……どうやらあと一歩、遅かったようだ。","ENG":"No, I think we are too late.","TWN":"不，我們好像晚了一步。"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"출장 때문에 잠시 자리를 비운 사이에 탈옥이라니…….","JPN":"出張のためにしばらく席を外していた間に脱獄とは……","ENG":"Trying to break out of prison while I was away on my business trip...?","TWN":"因為出差暫時離開，竟然就讓你越獄了……"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MEMBER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L8_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"아가씨의 연락이 늦었었다면 당신을 놓칠 뻔했군요.","JPN":"お嬢様からの連絡が遅れていたら、あなたを逃してしまうところでした。","ENG":"If Lady Elizabeth hadn't contacted me sooner, we would have missed you.","TWN":"要不是小姐及時聯繫，恐怕就錯過了。"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MEMBER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"버넷 경의 후예들인가……. 자네들도 참 끈질기군.","JPN":"バーネット卿の末裔たちか……君らも懲りないな。","ENG":"Descendants of Sir Burnett...? You guys are too persistent.","TWN":"是伯內特卿的後裔嗎……你們可真執著。"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"명줄이 질긴 건 당신입니다, 제임스. 감옥 생활은 어땠습니까?","JPN":"懲りないのはあなたでしょう、ジェームス。牢獄での生活はどうでしたか？","ENG":"No, it is your will to live that is persistent, James. How was prison life for you?","TWN":"是你命硬，詹姆斯。監獄裡的生活怎麼樣？"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"MEMBER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"첩보에 따르면, 병에 걸려서 미음도 못 삼킬 정도로 쇠약해졌다고 들었습니다만?","JPN":"諜報によると、病のせいで重湯も飲めないほどに衰弱していると聞きましたが。","ENG":"According to intel, I heard you were too sick to even eat rice gruel.","TWN":"根據線報，聽說你病入膏肓了，連米湯都咽不下去。"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MEMBER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"미안하지만 나는 여기서 순순히 잡혀줄 생각이 없네.","JPN":"悪いが、私はここで大人しく捕まるつもりはない。","ENG":"I'm sorry to inform you that I have no intention of getting caught by you here.","TWN":"對不起，我不打算在這裡乖乖被抓。"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L19_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"목숨이 다하기 전에…… 꼭 내 눈으로 <color=#ffd34c>보고 싶은 것</color>이 생겼거든.","JPN":"命が尽きる前に……必ずこの目で<color=#ffd34c>見たいもの</color>ができたからな。","ENG":"There is <color=#ffd34c>something I want to see</color>... before my time on earth ends.","TWN":"在生命結束之前……我有親眼<color=#ffd34c>想看的東西</color>。"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"그러니 정중히 부탁하겠네. 부디 비켜주겠나, 라이언 페리어?","JPN":"だから、丁寧にお願いしよう。どうか道を譲っていただけないだろうか？　ライアン・フェリエー。","ENG":"So, I would like to politely ask that you move aside, Ryan Ferrier.","TWN":"所以，我鄭重地拜託你，你能讓開嗎，瑞安·佩里？"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"흥, 들어줄 가치도 없는 부탁이군.","JPN":"ふん、聞く価値もないお願いですね。","ENG":"Hmph. That is a favour not even worth my time.","TWN":"哼，是個根本不值得回應的請求。"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"MEMBER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"내 손으로 당신을 끝장내게 된다니. 이거 모건이 아쉬워하겠군요.","JPN":"私の手であなたを始末することになるとは。タデウスが悔しがるでしょう。","ENG":"I'll finish you off myself. Oh, how upset Morgan will be.","TWN":"我竟然要親手了結你，要是摩根知道了，會很遺憾吧。"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MEMBER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};